  test('tags use consistent capitalization', () => {
    // All tags should be Title Case or consistent format
  });

  test('no overly long tags (max 20 chars)', () => {
    projects.forEach(project => {
      project.tags.forEach(tag => {
        expect(tag.length).toBeLessThanOrEqual(20);
      });
    });
  });

  test('common tags are spelled consistently', () => {
    // Check for variations like "AI" vs "ai" vs "Ai"
    // "DevTools" vs "Dev Tools" vs "devtools"
  });
});
```

### 6. heroStats Validation Tests
```typescript
describe('heroStats Validation', () => {
  test('project count matches actual projects array', () => {
    const statsValue = heroStats.find(s => s.label.includes('project'))?.value;
